import React, { useState, useEffect } from 'react';
import { NavLink } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

const NAV = [
  { path: '/',          icon: '⬡', label: 'Overview',       code: 'OVW' },
  { path: '/devices',   icon: '◈', label: 'Device Monitor', code: 'DVM' },
  { path: '/endpoints', icon: '⬢', label: 'Endpoints',      code: 'EPT' },
  { path: '/alerts',    icon: '⚠', label: 'Threat Alerts',  code: 'ALT' },
  { path: '/policy',    icon: '⛨', label: 'Policy Engine',  code: 'PLY' },
];

export default function Sidebar({ alertCount = 0 }) {
  const { user, logout } = useAuth();
  const [time, setTime] = useState(new Date());
  const [uptime, setUptime] = useState(0);

  useEffect(() => {
    const t = setInterval(() => { setTime(new Date()); setUptime(u => u + 1); }, 1000);
    return () => clearInterval(t);
  }, []);

  const fmt = (n) => String(n).padStart(2, '0');
  const hours = fmt(Math.floor(uptime / 3600));
  const mins  = fmt(Math.floor((uptime % 3600) / 60));
  const secs  = fmt(uptime % 60);

  return (
    <aside style={{
      position: 'fixed', left: 0, top: 0, bottom: 0, width: '220px',
      background: 'var(--bg-deep)',
      borderRight: '1px solid var(--border-dim)',
      display: 'flex', flexDirection: 'column',
      zIndex: 40,
    }}>
      {/* Top accent line */}
      <div style={{ height: '2px', background: 'linear-gradient(90deg, var(--accent-blue), var(--accent-cyan), transparent)' }} />

      {/* Logo */}
      <div style={{ padding: '20px 18px 16px', borderBottom: '1px solid var(--border-dim)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '6px' }}>
          <div style={{
            width: '32px', height: '32px',
            background: 'rgba(0,212,255,0.08)',
            border: '1px solid rgba(0,212,255,0.3)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: '16px', color: 'var(--accent-blue)',
            position: 'relative',
          }}>
            ⬡
            <div style={{ position: 'absolute', bottom: '-1px', right: '-1px', width: '6px', height: '6px', borderBottom: '1px solid var(--accent-blue)', borderRight: '1px solid var(--accent-blue)' }} />
          </div>
          <div>
            <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '15px', fontWeight: '700', color: 'var(--accent-blue)', letterSpacing: '0.05em' }} className="animate-flicker">EDTMRS</div>
            <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '8px', color: 'var(--text-dim)', letterSpacing: '0.12em' }}>v5.0 // SECURE</div>
          </div>
        </div>
        {/* Clock */}
        <div style={{
          fontFamily: "'JetBrains Mono', monospace", fontSize: '11px',
          color: 'var(--accent-cyan)', letterSpacing: '0.05em',
          background: 'rgba(0,255,204,0.04)', border: '1px solid rgba(0,255,204,0.1)',
          padding: '4px 8px', marginTop: '8px',
        }}>
          {time.toTimeString().slice(0,8)} UTC+{-time.getTimezoneOffset()/60}
        </div>
      </div>

      {/* System status */}
      <div style={{ padding: '10px 18px', borderBottom: '1px solid var(--border-dim)' }}>
        <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '8px', color: 'var(--text-dim)', letterSpacing: '0.15em', marginBottom: '6px' }}>SYS STATUS</div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '3px' }}>
          {[
            { label: 'CORE',    val: 'ACTIVE',  color: 'var(--accent-green)' },
            { label: 'WS',      val: 'LINKED',  color: 'var(--accent-cyan)' },
            { label: 'UPTIME',  val: `${hours}:${mins}:${secs}`, color: 'var(--accent-blue)' },
          ].map(s => (
            <div key={s.label} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-dim)' }}>{s.label}</span>
              <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: s.color }}>{s.val}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Navigation */}
      <nav style={{ flex: 1, padding: '10px 10px', overflowY: 'auto' }}>
        <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '8px', color: 'var(--text-dim)', letterSpacing: '0.15em', padding: '6px 8px', marginBottom: '4px' }}>MODULES</div>
        {NAV.map((item) => (
          <NavLink key={item.path} to={item.path} end={item.path === '/'}
            style={({ isActive }) => ({
              display: 'flex', alignItems: 'center', gap: '10px',
              padding: '9px 10px', marginBottom: '2px',
              textDecoration: 'none',
              background: isActive ? 'rgba(0,212,255,0.08)' : 'transparent',
              borderLeft: isActive ? '2px solid var(--accent-blue)' : '2px solid transparent',
              borderRight: isActive ? '1px solid rgba(0,212,255,0.15)' : '1px solid transparent',
              transition: 'all 0.15s',
              position: 'relative',
            })}
          >
            {({ isActive }) => (<>
              <span style={{ fontSize: '13px', color: isActive ? 'var(--accent-blue)' : 'var(--text-dim)', width: '16px', textAlign: 'center' }}>{item.icon}</span>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: '13px', fontWeight: '600', color: isActive ? 'var(--text-primary)' : 'var(--text-dim)', letterSpacing: '0.02em' }}>{item.label}</div>
                <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '8px', color: isActive ? 'var(--accent-blue)' : 'var(--text-muted)', letterSpacing: '0.1em' }}>{item.code}</div>
              </div>
              {item.label === 'Threat Alerts' && alertCount > 0 && (
                <span style={{
                  fontFamily: "'Space Mono', monospace", fontSize: '9px',
                  background: 'var(--accent-red)', color: '#fff',
                  padding: '2px 6px', borderRadius: '2px',
                  animation: 'pulse-glow 1s infinite',
                }}>{alertCount > 99 ? '99+' : alertCount}</span>
              )}
            </>)}
          </NavLink>
        ))}
      </nav>

      {/* User info */}
      <div style={{ padding: '12px 18px', borderTop: '1px solid var(--border-dim)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '8px' }}>
          <div style={{
            width: '28px', height: '28px', background: 'rgba(0,212,255,0.1)',
            border: '1px solid rgba(0,212,255,0.3)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontFamily: "'Space Mono', monospace", fontSize: '11px',
            color: 'var(--accent-blue)', fontWeight: '700',
          }}>
            {user?.username?.[0]?.toUpperCase() || 'A'}
          </div>
          <div>
            <div style={{ fontSize: '13px', fontWeight: '600', color: 'var(--text-primary)' }}>{user?.username}</div>
            <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--accent-cyan)', textTransform: 'uppercase', letterSpacing: '0.1em' }}>{user?.role}</div>
          </div>
        </div>
        <button onClick={logout} style={{
          width: '100%', textAlign: 'left', background: 'transparent',
          border: '1px solid var(--border-dim)', color: 'var(--text-dim)',
          fontFamily: "'Space Mono', monospace", fontSize: '9px',
          letterSpacing: '0.1em', textTransform: 'uppercase',
          padding: '6px 10px', cursor: 'pointer',
          transition: 'all 0.15s',
        }}
          onMouseEnter={e => { e.target.style.color = 'var(--accent-red)'; e.target.style.borderColor = 'rgba(255,51,102,0.4)'; }}
          onMouseLeave={e => { e.target.style.color = 'var(--text-dim)'; e.target.style.borderColor = 'var(--border-dim)'; }}
        >
          ⇥ TERMINATE SESSION
        </button>
      </div>
    </aside>
  );
}
